#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-06-10

# Test: ork-rubric/1.0 rubric contract validation (#2347)
#
# Grading skills (verify, assess, review-pr) ship machine-readable rubrics as
# src/skills/<skill>/rubric.json conforming to the shared contract in
# src/skills/shared/rubric.schema.json. This lint keeps every rubric file
# structurally valid so CI, dashboards, and the memory graph can rely on it:
#   - valid JSON, rubric == "ork-rubric/1.0", non-empty dimensions[]
#   - every weight in [0,1]; weights sum to 1.0 (+/- 0.001)
#   - min_blocker <= min_pass when both present
#   - band score ranges within [0,10] and score_min <= score_max
#   - no unknown keys at any level (mirrors the schema's additionalProperties: false)
# The schema file itself must also parse. No new deps — plain node -e.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../../.." && pwd)"
SCHEMA_FILE="$REPO_ROOT/src/skills/shared/rubric.schema.json"

FAILED=0
CHECKED=0

# 1. The shared schema file must exist and parse as JSON.
if [[ ! -f "$SCHEMA_FILE" ]]; then
  echo "FAIL: schema file missing: $SCHEMA_FILE"
  exit 1
fi
if ! node -e "JSON.parse(require('fs').readFileSync('$SCHEMA_FILE', 'utf8'))" 2>/dev/null; then
  echo "FAIL: schema file is not valid JSON: ${SCHEMA_FILE#"$REPO_ROOT"/}"
  exit 1
fi

# 2. Validate every src/skills/*/rubric.json against the ork-rubric/1.0 contract.
while IFS= read -r rubric_file; do
  [[ -z "$rubric_file" ]] && continue
  CHECKED=$((CHECKED + 1))
  rel="${rubric_file#"$REPO_ROOT"/}"

  errors="$(node -e '
    const fs = require("fs");
    const file = process.argv[1];
    const errs = [];
    let r;
    try {
      r = JSON.parse(fs.readFileSync(file, "utf8"));
    } catch (e) {
      console.log(`invalid JSON: ${e.message}`);
      process.exit(0);
    }
    // Mirror the schema additionalProperties: false at every object level --
    // a mistyped key (min_passs, wieght) must fail, not silently pass.
    const ALLOWED = {
      root: ["rubric", "skill", "description", "source", "composite", "dimensions"],
      composite: ["min_pass"],
      dimension: ["name", "weight", "min_pass", "min_blocker", "bands", "description"],
      band: ["score_min", "score_max", "label", "description"],
    };
    const checkKeys = (obj, allowed, tag) => {
      if (!obj || typeof obj !== "object" || Array.isArray(obj)) return;
      for (const k of Object.keys(obj)) {
        if (!allowed.includes(k)) errs.push(`${tag}: unknown key "${k}" (schema is additionalProperties: false)`);
      }
    };
    checkKeys(r, ALLOWED.root, "root");
    if (r.rubric !== "ork-rubric/1.0") {
      errs.push(`rubric field must be "ork-rubric/1.0" (got ${JSON.stringify(r.rubric)})`);
    }
    if (typeof r.skill !== "string" || r.skill.length === 0) {
      errs.push("skill must be a non-empty string");
    }
    if (!Array.isArray(r.dimensions) || r.dimensions.length === 0) {
      errs.push("dimensions must be a non-empty array");
    } else {
      let sum = 0;
      for (const [i, d] of r.dimensions.entries()) {
        const tag = `dimensions[${i}] (${d && d.name ? d.name : "unnamed"})`;
        checkKeys(d, ALLOWED.dimension, tag);
        if (!d || typeof d.name !== "string" || d.name.length === 0) {
          errs.push(`${tag}: name must be a non-empty string`);
        }
        if (typeof d.weight !== "number" || d.weight < 0 || d.weight > 1) {
          errs.push(`${tag}: weight must be a number in [0,1] (got ${JSON.stringify(d.weight)})`);
        } else {
          sum += d.weight;
        }
        for (const key of ["min_pass", "min_blocker"]) {
          if (d[key] !== undefined && (typeof d[key] !== "number" || d[key] < 0 || d[key] > 10)) {
            errs.push(`${tag}: ${key} must be a number in [0,10]`);
          }
        }
        if (typeof d.min_pass === "number" && typeof d.min_blocker === "number" && d.min_blocker > d.min_pass) {
          errs.push(`${tag}: min_blocker (${d.min_blocker}) must be <= min_pass (${d.min_pass})`);
        }
        if (d.bands !== undefined) {
          if (!Array.isArray(d.bands) || d.bands.length === 0) {
            errs.push(`${tag}: bands must be a non-empty array when present`);
          } else {
            for (const [j, b] of d.bands.entries()) {
              const btag = `${tag} bands[${j}]`;
              checkKeys(b, ALLOWED.band, btag);
              if (!b || typeof b.label !== "string" || b.label.length === 0) {
                errs.push(`${btag}: label must be a non-empty string`);
              }
              for (const key of ["score_min", "score_max"]) {
                if (typeof b[key] !== "number" || b[key] < 0 || b[key] > 10) {
                  errs.push(`${btag}: ${key} must be a number in [0,10]`);
                }
              }
              if (typeof b.score_min === "number" && typeof b.score_max === "number" && b.score_min > b.score_max) {
                errs.push(`${btag}: score_min (${b.score_min}) must be <= score_max (${b.score_max})`);
              }
            }
          }
        }
      }
      if (Math.abs(sum - 1.0) > 0.001) {
        errs.push(`dimension weights must sum to 1.0 +/- 0.001 (got ${sum.toFixed(4)})`);
      }
    }
    if (r.composite !== undefined) {
      checkKeys(r.composite, ALLOWED.composite, "composite");
      if (typeof r.composite !== "object" || r.composite === null ||
          typeof r.composite.min_pass !== "number" ||
          r.composite.min_pass < 0 || r.composite.min_pass > 10) {
        errs.push("composite.min_pass must be a number in [0,10]");
      }
    }
    for (const e of errs) console.log(e);
  ' "$rubric_file")"

  if [[ -n "$errors" ]]; then
    while IFS= read -r err; do
      echo "FAIL: $rel — $err"
    done <<< "$errors"
    FAILED=1
  fi
done < <(find "$REPO_ROOT/src/skills" -mindepth 2 -maxdepth 2 -name "rubric.json" | sort)

echo ""
echo "Checked $CHECKED rubric.json files against the ork-rubric/1.0 contract"

if [[ $CHECKED -eq 0 ]]; then
  echo "FAIL: no src/skills/*/rubric.json found — verify/assess/review-pr backfills missing (#2347)"
  exit 1
fi

if [[ $FAILED -eq 1 ]]; then
  echo "FAIL: rubric contract violations found — fix the rubric.json files above (schema: src/skills/shared/rubric.schema.json)"
  exit 1
fi

echo "PASS: all skill rubric.json files conform to ork-rubric/1.0"
exit 0
